Code.Terraform:
```hcl
# Terraform: Lightsail インスタンスで公開ポートが開いていないことを確認
resource "aws_lightsail_instance_public_ports" "<example_resource_name>" {
  instance_name = "<example_resource_name>"

  # 重要: port_info ブロックがない -> 公開ポートが設定されていない（すべて閉じる）
  dynamic "port_info" {
    for_each = []
    content {
      from_port = 0
      to_port   = 0
      protocol  = "tcp"
    }
  }
}
```
